mapper.select:
SELECT id, user_id, group_name, word, created_at
FROM hotword
WHERE id = #{id}

SELECT id, user_id, group_name, word, created_at
FROM hotword
WHERE user_id = #{userId}
  AND group_name = #{groupName}
ORDER BY id ASC

SELECT EXISTS(
    SELECT 1 FROM hotword
    WHERE user_id = #{userId}
      AND group_name = #{groupName}
      AND word = #{word}
)
